/* card-clickthrough.js */
(() => {
  const cfg = window.CARD_CLICKTHROUGH || {};
  const sectionIds = Array.isArray(cfg.sectionIds) ? cfg.sectionIds : [];
  if (!sectionIds.length) return;

  const rootSelector = sectionIds
    .map((id) => `section[data-section-id="${id}"] .list-item`)
    .join(",");

  // Delegate: works even with Squarespace's Ajax-y page loads
  document.addEventListener("click", (e) => {
    // Respect new-tab / right-click behavior
    if (e.defaultPrevented) return;
    if (e.button !== 0) return; // only left click
    if (e.metaKey || e.ctrlKey || e.shiftKey || e.altKey) return;

    const item = e.target.closest(rootSelector);
    if (!item) return;

    // Don't hijack clicks on real interactive elements
    if (e.target.closest('a, button, input, textarea, select, label')) return;

    const btn = item.querySelector(
      'a.list-item-content__button.sqs-block-button-element[href]'
    );
    if (!btn) return;

    // Navigate to the same URL as the yellow button
    window.location.href = btn.href;
  });
})();
